preToolUse.powershell:
param($input)
$payload = $input | ConvertFrom-Json
$toolName = $payload.tool_name
$toolInput = $payload.tool_input | ConvertTo-Json
if ($toolName -eq 'run_sql') {
  $sql = $payload.tool_input.sqlScript
  $dryRun = $payload.tool_input.dryRun
  # Block DROP TABLE unless it's a dry run
  if ($sql -match '(?i)\bDROP\s+TABLE\b' -and -not $dryRun) {
    Write-Output '{"decision":"block","reason":"DROP TABLE detected. Set dryRun=true first to preview, or include the word CONFIRMED in your prompt to proceed."}'
    exit 1
  }
  # Block TRUNCATE TABLE
  if ($sql -match '(?i)\bTRUNCATE\s+TABLE\b' -and -not $dryRun) {
    Write-Output '{"decision":"block","reason":"TRUNCATE TABLE detected. This permanently removes all rows. Use dryRun=true first."}'
    exit 1
  }
  # Block DELETE without WHERE clause
  if ($sql -match '(?i)\bDELETE\s+FROM\s+\w+\s*$' -and -not $dryRun) {
    Write-Output '{"decision":"block","reason":"DELETE without WHERE clause detected. This deletes all rows. Use dryRun=true first."}'
    exit 1
  }
}
exit 0
